import React, { useState } from 'react';

const MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
const DOW = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];

export default function DatePicker() {
  const [view, setView] = useState(new Date());
  const [selected, setSelected] = useState(null);

  const y = view.getFullYear();
  const m = view.getMonth();
  const firstDay = new Date(y, m, 1).getDay();
  const daysInMonth = new Date(y, m + 1, 0).getDate();
  const cells = [...Array(firstDay).fill(null), ...Array.from({ length: daysInMonth }, (_, i) => i + 1)];

  const isSel = (d) =>
    selected && selected.getFullYear() === y && selected.getMonth() === m && selected.getDate() === d;

  const cell = {
    height: 36,
    border: 'none',
    background: 'none',
    cursor: 'pointer',
    borderRadius: 6,
    fontSize: 14,
  };

  return (
    <div style={{ width: 280, border: '1px solid #e5e7eb', borderRadius: 10, padding: 12 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
        <button onClick={() => setView(new Date(y, m - 1, 1))} style={{ cursor: 'pointer' }}>‹</button>
        <strong>{MONTHS[m]} {y}</strong>
        <button onClick={() => setView(new Date(y, m + 1, 1))} style={{ cursor: 'pointer' }}>›</button>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 2 }}>
        {DOW.map((d) => (
          <div key={d} style={{ textAlign: 'center', color: '#9ca3af', fontSize: 12, padding: '4px 0' }}>{d}</div>
        ))}
        {cells.map((d, i) =>
          d === null ? (
            <div key={`b${i}`} />
          ) : (
            <button
              key={d}
              onClick={() => setSelected(new Date(y, m, d))}
              style={{ ...cell, background: isSel(d) ? '#2563eb' : 'none', color: isSel(d) ? '#fff' : '#111' }}
            >
              {d}
            </button>
          )
        )}
      </div>
      <p style={{ marginTop: 10, color: '#666' }}>
        {selected ? `Selected: ${selected.toLocaleDateString()}` : 'No date selected'}
      </p>
    </div>
  );
}

