import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-date-picker',
  template: `
    <div style="width: 280px; border: 1px solid #e5e7eb; border-radius: 10px; padding: 12px;">
      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px;">
        <button (click)="prev()" style="cursor: pointer;">‹</button>
        <strong>{{ months[view.getMonth()] }} {{ view.getFullYear() }}</strong>
        <button (click)="next()" style="cursor: pointer;">›</button>
      </div>
      <div style="display: grid; grid-template-columns: repeat(7, 1fr); gap: 2px;">
        <div *ngFor="let d of dow" style="text-align: center; color: #9ca3af; font-size: 12px; padding: 4px 0;">{{ d }}</div>
        <ng-container *ngFor="let d of cells; let i = index">
          <div *ngIf="d === null"></div>
          <button
            *ngIf="d !== null"
            (click)="pick(d)"
            [style.background]="isSel(d) ? '#2563eb' : 'transparent'"
            [style.color]="isSel(d) ? '#fff' : '#111'"
            style="height: 36px; border: none; cursor: pointer; border-radius: 6px; font-size: 14px;"
          >{{ d }}</button>
        </ng-container>
      </div>
      <p style="margin-top: 10px; color: #666;">{{ selected ? 'Selected: ' + selected.toLocaleDateString() : 'No date selected' }}</p>
    </div>
  `,
})
export class DatePickerComponent {
  view = new Date();
  selected: Date | null = null;
  months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
  dow = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];

  get cells(): (number | null)[] {
    const y = this.view.getFullYear();
    const m = this.view.getMonth();
    const first = new Date(y, m, 1).getDay();
    const days = new Date(y, m + 1, 0).getDate();
    const arr: (number | null)[] = Array(first).fill(null);
    for (let d = 1; d <= days; d++) {
      arr.push(d);
    }
    return arr;
  }

  prev(): void {
    this.view = new Date(this.view.getFullYear(), this.view.getMonth() - 1, 1);
  }

  next(): void {
    this.view = new Date(this.view.getFullYear(), this.view.getMonth() + 1, 1);
  }

  pick(d: number): void {
    this.selected = new Date(this.view.getFullYear(), this.view.getMonth(), d);
  }

  isSel(d: number): boolean {
    const s = this.selected;
    return (
      !!s &&
      s.getFullYear() === this.view.getFullYear() &&
      s.getMonth() === this.view.getMonth() &&
      s.getDate() === d
    );
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Date Picker Demo</h1>
      <app-date-picker></app-date-picker>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, DatePickerComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
